module top_module(
   input         clock, write, reset,
   input [15:0]  writeData,
   output [15:0] data);reg [15:0]    input_data = 16'b0;

   always @ (posedge clock) begin 
      if (reset)
         input_data = 16'b0;
      else if (write)
         input_data = writeData;
   end

   assign data = input_data;
endmodule
